export const FREQUENT_FOOD_IDS = [
  'white-rice', 'basmati-rice', 'chicken-breast', 'egg-whole',
  'oats', 'banana', 'greek-yogurt', 'whole-milk',
  'broccoli', 'almonds', 'beef-burger', 'french-fries',
  'shawarma-chicken', 'hummus', 'dates', 'pita-bread',
];

export function searchFoods(query: string): Food[] {
  const q = query.toLowerCase().trim();
  if (!q) return FREQUENT_FOOD_IDS.map(id => FOODS.find(f => f.id === id)!).filter(Boolean);
  return FOODS.filter(f =>
    f.name.toLowerCase().includes(q) ||
    f.category.toLowerCase().includes(q)
  ).slice(0, 30);
}

export function getFoodById(id: string): Food | undefined {
  return FOODS.find(f => f.id === id);
}

/**
 * Scale all macros linearly by the logged portion (grams).
 * All per100g values represent the food as eaten (cooked weight).
 * Formula: nutrient = (per100g_value / 100) × grams
 */
export function calcNutrition(food: Food, grams: number) {
  const r = grams / 100;
  return {
    calories: Math.round(food.per100g.calories * r),
    protein:  Math.round(food.per100g.protein  * r * 10) / 10,
    fat:      Math.round(food.per100g.fat       * r * 10) / 10,
    carbs:    Math.round(food.per100g.carbs     * r * 10) / 10,
    fiber:    Math.round(food.per100g.fiber     * r * 10) / 10,
  };
}
